#include <iostream>

int tripleIt(int x)
{
    return x * 3;
}

int addOffset(int value, int offset)
{
    return value + offset;  // Fixed: changed - to +
}

int scaleDown(int value, int divisor)
{
    return value / divisor;
}

int main()
{
    int value{}, multiplier{};
    std::cin >> value >> multiplier;

    int tripled = tripleIt(value);
    int withOffset = addOffset(tripled, 100);
    int result = scaleDown(withOffset, multiplier);

    std::cout << result << '\n';

    return 0;
}

